1	/**
2	 * LayerInfinite MCP Server — rest-client.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * V2: LiApiClient (LI REST API) + UpstreamMCPClient (MCP JSON-RPC proxy).
5	 *
6	 * LiApiClient replaces V1 RestClient — fetches scores, policy decisions,
7	 * and logs outcomes to the LayerInfinite REST API.
8	 *
9	 * UpstreamMCPClient implements MCP JSON-RPC over HTTP for proxying
10	 * tools/list and tools/call to upstream MCP servers, with circuit
11	 * breaker integration and session caching.
12	 * ══════════════════════════════════════════════════════════════
13	 */
14	
15	import type { GatewayConfig, UpstreamServer } from './config.js';
16	import type { ScoredAction, PolicyDecision, OutcomePayload } from './types.js';
17	import { UpstreamRegistry } from './upstream-registry.js';
18	import type { FailOpenState } from './types.js';
19	import {
20	  recordUpstreamSuccess,
21	  recordUpstreamFailure,
22	} from './fail-open.js';
23	import { logger } from './logger.js';
24	
25	const log = logger.forTool('rest-client');
26	
27	// ── V1-compatible types (preserved) ──────────────────────────
28	
29	export interface LIApiError {
30	  error: string;
31	  code: string;
32	  message?: string;
33	  details?: unknown;
34	}
35	
36	export interface LIApiResponse<T> {
37	  ok: true;
38	  status: number;
39	  data: T;
40	}
41	
42	export interface LIApiErrorResponse {
43	  ok: false;
44	  status: number;
45	  error: LIApiError;
46	}
47	
48	export type LIResult<T> = LIApiResponse<T> | LIApiErrorResponse;
49	
50	// ── V2 new types ─────────────────────────────────────────────
51	
52	export interface RawUpstreamTool {
53	  name: string;
54	  description: string;
55	  inputSchema: Record<string, unknown>;
56	  upstreamName: string;
57	}
58	
59	export interface UpstreamCallResult {
60	  content: Array<{ type: string; [key: string]: unknown }>;
61	  isError?: boolean;
62	}
63	
64	// ── Constants ────────────────────────────────────────────────
65	
66	const LI_API_TIMEOUT_MS = 15_000;
67	const MCP_CALL_TIMEOUT_MS = 30_000;
68	const RETRYABLE_STATUS_CODES = new Set([429, 502, 503, 504]);
69	const MAX_RETRIES = 2;
70	const BASE_RETRY_DELAY_MS = 500;
71	
72	// Per-upstream connection concurrency
73	const DEFAULT_MAX_CONCURRENT_UPSTREAM = 100;
74	
75	function getMaxConcurrentUpstream(): number {
76	  const v = Number.parseInt(process.env.LAYERINFINITE_MAX_UPSTREAM_CONCURRENT ?? '', 10);
77	  return Number.isFinite(v) && v > 0 ? v : DEFAULT_MAX_CONCURRENT_UPSTREAM;
78	}
79	
80	// ══════════════════════════════════════════════════════════════
81	// LiApiClient — LI REST API communication
82	// ══════════════════════════════════════════════════════════════
83	
84	export class LiApiClient {
85	  private readonly baseUrl: string;
86	  private readonly primaryKey: string;
87	  private readonly secondaryKey: string | undefined;
88	
89	  constructor(config: GatewayConfig) {
90	    this.baseUrl = config.baseUrl;
91	    this.primaryKey = config.apiKey;
92	    this.secondaryKey = config.apiKeySecondary;
93	  }
94	
95	  private buildHeaders(apiKey?: string): Record<string, string> {
96	    return {
97	      'X-API-Key': apiKey ?? this.primaryKey,
98	      'Content-Type': 'application/json',
99	      'User-Agent': '@layerinfinite/mcp-server/2.0.0',
100	    };
101	  }
102	
103	  /** Fetch scored actions for a task type. */
104	  async getScores(
105	    taskType: string,
106	    customerId: string,
107	    agentId: string,
108	  ): Promise<ScoredAction[]> {
109	    const result = await this.get<{ scores: ScoredAction[] }>(
110	      '/v1/get-scores',
111	      { task_type: taskType, customer_id: customerId, agent_id: agentId },
112	    );
113	    if (!result.ok) {
114	      log.warn('getScores failed', { code: result.error.code });
115	      return [];
116	    }
117	    return result.data.scores ?? [];
118	  }
119	
120	  /** Fetch policy decision for a task type. */
121	  async getPolicyDecision(
122	    taskType: string,
123	    customerId: string,
124	    agentId: string,
125	  ): Promise<PolicyDecision | null> {
126	    const result = await this.get<{ decision: PolicyDecision | null }>(
127	      '/v1/recommendations',
128	      { task_type: taskType, customer_id: customerId, agent_id: agentId },
129	    );
130	    if (!result.ok) {
131	      log.warn('getPolicyDecision failed', { code: result.error.code });
132	      return null;
133	    }
134	    return result.data.decision ?? null;
135	  }
136	
137	  /** Fire-and-forget outcome logging. Returns true if successful. */
138	  async logOutcome(payload: OutcomePayload): Promise<boolean> {
139	    const result = await this.post<{ accepted: boolean }>(
140	      '/v1/log-outcome',
141	      payload as unknown as Record<string, unknown>,
142	    );
143	    return result.ok;
144	  }
145	
146	  /** Get recommendations for a task type (legacy / li_recommend support). */
147	  async getRecommendations(
148	    taskType: string,
149	    customerId: string,
150	    agentId: string,
151	  ): Promise<ScoredAction[]> {
152	    return this.getScores(taskType, customerId, agentId);
153	  }
154	
155	  // ── HTTP helpers (preserved from V1) ─────────────────────
156	
157	  private async get<T>(
158	    path: string,
159	    params?: Record<string, string>,
160	  ): Promise<LIResult<T>> {
161	    const url = new URL(`${this.baseUrl}${path}`);
162	    if (params) {
163	      for (const [key, value] of Object.entries(params)) {
164	        if (value !== undefined && value !== '') {
165	          url.searchParams.set(key, value);
166	        }
167	      }
168	    }
169	    return this.requestWithRetry<T>(url.toString(), { method: 'GET' });
170	  }
171	
172	  private async post<T>(
173	    path: string,
174	    body: Record<string, unknown>,
175	  ): Promise<LIResult<T>> {
176	    return this.requestWithRetry<T>(`${this.baseUrl}${path}`, {
177	      method: 'POST',
178	      body: JSON.stringify(body),
179	    });
180	  }
181	
182	  private async requestWithRetry<T>(
183	    url: string,
184	    init: RequestInit,
185	  ): Promise<LIResult<T>> {
186	    let lastResult: LIResult<T> | null = null;
187	
188	    for (let attempt = 0; attempt <= MAX_RETRIES; attempt++) {
189	      if (attempt > 0) {
190	        const delay = BASE_RETRY_DELAY_MS * Math.pow(2, attempt - 1);
191	        log.warn('Retrying LI API request', { url, attempt: attempt + 1, delay_ms: delay });
192	        await this.sleep(delay);
193	      }
194	
195	      const result = await this.request<T>(url, init);
196	      if (result.ok) return result;
197	
198	      lastResult = result;
199	      const isRetryable = RETRYABLE_STATUS_CODES.has(result.status)
200	        || result.error.code === 'TIMEOUT'
201	        || result.error.code === 'NETWORK_ERROR';
202	      if (!isRetryable) break;
203	    }
204	
205	    return lastResult!;
206	  }
207	
208	  private async request<T>(
209	    url: string,
210	    init: RequestInit,
211	    usedSecondary = false,
212	  ): Promise<LIResult<T>> {
213	    const controller = new AbortController();
214	    const timeout = setTimeout(() => controller.abort(), LI_API_TIMEOUT_MS);
215	    const startMs = Date.now();
216	
217	    try {
218	      const response = await fetch(url, {
219	        ...init,
220	        headers: { ...this.buildHeaders(), ...(init.headers as Record<string, string> ?? {}) },
221	        signal: controller.signal,
222	      });
223	
224	      const latencyMs = Date.now() - startMs;
225	      const isJson = response.headers.get('content-type')?.includes('application/json');
226	
227	      if (response.ok) {
228	        const data = isJson ? (await response.json()) as T : ({} as T);
229	        log.debug('LI API response', { method: init.method, url, status: response.status, latency_ms: latencyMs });
230	        return { ok: true, status: response.status, data };
231	      }
232	
233	      // Zero-downtime key rotation: retry with secondary key on auth failure
234	      if ((response.status === 401 || response.status === 403) && this.secondaryKey && !usedSecondary) {
235	        clearTimeout(timeout);
236	        log.info('Primary key rejected — retrying with secondary key');
237	        return this.request<T>(url, {
238	          ...init,
239	          headers: { ...this.buildHeaders(this.secondaryKey), ...(init.headers as Record<string, string> ?? {}) },
240	        }, true);
241	      }
242	
243	      const errorBody: LIApiError = isJson
244	        ? (await response.json()) as LIApiError
245	        : { error: 'API Error', code: 'UNKNOWN', message: await response.text() };
246	
247	      log.warn('LI API error', { method: init.method, url, status: response.status, error_code: errorBody.code });
248	      return { ok: false, status: response.status, error: errorBody };
249	    } catch (err) {
250	      const latencyMs = Date.now() - startMs;
251	      if (err instanceof DOMException && err.name === 'AbortError') {
252	        log.error('LI API timeout', { method: init.method, url, timeout_ms: LI_API_TIMEOUT_MS });
253	        return {
254	          ok: false,
255	          status: 0,
256	          error: { error: 'Request timed out', code: 'TIMEOUT', message: `Request timed out after ${LI_API_TIMEOUT_MS}ms` },
257	        };
258	      }
259	
260	      const message = err instanceof Error ? err.message : String(err);
261	      log.error('LI API network error', { method: init.method, url, error: message });
262	      return {
263	        ok: false,
264	        status: 0,
265	        error: { error: 'Network error', code: 'NETWORK_ERROR', message },
266	      };
267	    } finally {
268	      clearTimeout(timeout);
269	    }
270	  }
271	
272	  private sleep(ms: number): Promise<void> {
273	    return new Promise((resolve) => setTimeout(resolve, ms));
274	  }
275	}
276	
277	// ══════════════════════════════════════════════════════════════
278	// UpstreamMCPClient — MCP JSON-RPC proxy to upstream servers
279	// ══════════════════════════════════════════════════════════════
280	
281	export class UpstreamMCPClient {
282	  private readonly registry: UpstreamRegistry;
283	  private readonly failOpenState: FailOpenState;
284	  private readonly sessions = new Map<string, string>();
285	  private requestCounter = 0;
286	  private readonly activeConnections = new Map<string, number>();
287	  private readonly maxConcurrent: number;
288	  private readonly initialized = new Map<string, boolean>();
289	  private readonly initPromises = new Map<string, Promise<void>>();
290	
291	  constructor(registry: UpstreamRegistry) {
292	    this.registry = registry;
293	    this.failOpenState = registry.getFailOpenState();
294	    this.maxConcurrent = getMaxConcurrentUpstream();
295	  }
296	
297	  /** Fetch all tools from all healthy upstreams. */
298	  async listTools(): Promise<RawUpstreamTool[]> {
299	    const tools: RawUpstreamTool[] = [];
300	    const healthy = this.getHealthyUpstreams();
301	    const entries = this.registry.getAllUpstreams().filter((e) => healthy.includes(e.server.name));
302	
303	    const results = await Promise.allSettled(
304	      entries.map(async (entry) => {
305	        const rawTools = await this.fetchUpstreamTools(entry.server);
306	        return rawTools.map((t) => ({
307	          ...t,
308	          upstreamName: entry.server.name,
309	        }));
310	      }),
311	    );
312	
313	    for (const result of results) {
314	      if (result.status === 'fulfilled') {
315	        tools.push(...result.value);
316	      }
317	    }
318	
319	    return tools;
320	  }
321	
322	  /** Call a tool on a specific upstream server. */
323	  async callTool(
324	    upstreamName: string,
325	    toolName: string,
326	    args: Record<string, unknown>,
327	  ): Promise<UpstreamCallResult> {
328	    const entry = this.registry.getUpstream(upstreamName);
329	    if (!entry) {
330	      throw new Error(`Upstream "${upstreamName}" not found`);
331	    }
332	
333	    await this.ensureInitialized(entry.server);
334	
335	    try {
336	      const result = await this.mcpRequest<UpstreamCallResult>(
337	        entry.server,
338	        'tools/call',
339	        { name: toolName, arguments: args },
340	      );
341	      recordUpstreamSuccess(this.failOpenState, upstreamName);
342	      return result;
343	    } catch (err) {
344	      recordUpstreamFailure(this.failOpenState, upstreamName);
345	      throw err;
346	    }
347	  }
348	
349	  /** Get list of healthy upstream names (circuit closed + last health check OK). */
350	  getHealthyUpstreams(): string[] {
351	    return this.registry.getAllUpstreams()
352	      .filter((e) => this.registry.isHealthy(e.server.name))
353	      .map((e) => e.server.name);
354	  }
355	
356	  /** Start periodic health checks on all upstreams. */
357	  startHealthChecks(): void {
358	    this.registry.startHealthChecks();
359	  }
360	
361	  /** Stop periodic health checks. */
362	  stopHealthChecks(): void {
363	    this.registry.stopHealthChecks();
364	  }
365	
366	  // ── Private: MCP JSON-RPC ────────────────────────────────
367	
368	  private async ensureInitialized(server: UpstreamServer): Promise<void> {
369	    if (this.initialized.get(server.name)) return;
370	
371	    const existing = this.initPromises.get(server.name);
372	    if (existing) return existing;
373	
374	    const promise = this.doInitialize(server);
375	    this.initPromises.set(server.name, promise);
376	
377	    try {
378	      await promise;
379	    } finally {
380	      this.initPromises.delete(server.name);
381	    }
382	  }
383	
384	  private async doInitialize(server: UpstreamServer): Promise<void> {
385	    const body = JSON.stringify({
386	      jsonrpc: '2.0',
387	      method: 'initialize',
388	      params: {
389	        protocolVersion: '2024-11-05',
390	        capabilities: {},
391	        clientInfo: { name: 'layerinfinite-gateway', version: '2.0.0' },
392	      },
393	      id: 0,
394	    });
395	
396	    const headers: Record<string, string> = {
397	      'Content-Type': 'application/json',
398	      Accept: 'application/json',
399	    };
400	    if (server.apiKey) headers['Authorization'] = `Bearer ${server.apiKey}`;
401	
402	    const response = await fetch(server.url, {
403	      method: 'POST',
404	      headers,
405	      body,
406	      signal: AbortSignal.timeout(10_000),
407	    });
408	
409	    if (!response.ok) {
410	      throw new Error(`Initialize failed for ${server.name}: HTTP ${response.status}`);
411	    }
412	
413	    const sessionId = response.headers.get('Mcp-Session-Id');
414	    if (sessionId) {
415	      this.sessions.set(server.name, sessionId);
416	    }
417	
418	    // Send initialized notification (no id = notification per MCP spec)
419	    const notifBody = JSON.stringify({
420	      jsonrpc: '2.0',
421	      method: 'notifications/initialized',
422	      params: {},
423	    });
424	
425	    const notifHeaders: Record<string, string> = { 'Content-Type': 'application/json' };
426	    if (sessionId) notifHeaders['Mcp-Session-Id'] = sessionId;
427	    if (server.apiKey) notifHeaders['Authorization'] = `Bearer ${server.apiKey}`;
428	
429	    await fetch(server.url, {
430	      method: 'POST',
431	      headers: notifHeaders,
432	      body: notifBody,
433	      signal: AbortSignal.timeout(5_000),
434	    });
435	
436	    this.initialized.set(server.name, true);
437	    log.info('Upstream initialized', { name: server.name });
438	  }
439	
440	  private async fetchUpstreamTools(server: UpstreamServer): Promise<Omit<RawUpstreamTool, 'upstreamName'>[]> {
441	    await this.ensureInitialized(server);
442	    const result = await this.mcpRequest<{ tools: Array<{ name: string; description: string; inputSchema: Record<string, unknown> }> }>(
443	      server,
444	      'tools/list',
445	    );
446	    return (result.tools ?? []).map((t) => ({
447	      name: t.name,
448	      description: t.description ?? '',
449	      inputSchema: t.inputSchema ?? { type: 'object', properties: {} },
450	    }));
451	  }
452	
453	  private async mcpRequest<T>(
454	    server: UpstreamServer,
455	    method: string,
456	    params?: Record<string, unknown>,
457	  ): Promise<T> {
458	    // ── Concurrency gate ────────────────────────────────────
459	    const active = this.activeConnections.get(server.name) ?? 0;
460	    if (active >= this.maxConcurrent) {
461	      throw new Error(
462	        `Upstream "${server.name}" concurrency limit reached (${active}/${this.maxConcurrent})`,
463	      );
464	    }
465	    this.activeConnections.set(server.name, active + 1);
466	
467	    const id = ++this.requestCounter;
468	    const body = JSON.stringify({
469	      jsonrpc: '2.0',
470	      method,
471	      params: params ?? {},
472	      id,
473	    });
474	
475	    const headers: Record<string, string> = {
476	      'Content-Type': 'application/json',
477	      Accept: 'application/json',
478	    };
479	
480	    if (server.apiKey) {
481	      headers['Authorization'] = `Bearer ${server.apiKey}`;
482	    }
483	
484	    const sessionId = this.sessions.get(server.name);
485	    if (sessionId) {
486	      headers['Mcp-Session-Id'] = sessionId;
487	    }
488	
489	    const controller = new AbortController();
490	    const timeout = setTimeout(() => controller.abort(), MCP_CALL_TIMEOUT_MS);
491	
492	    try {
493	      const response = await fetch(server.url, {
494	        method: 'POST',
495	        headers,
496	        body,
497	        signal: controller.signal,
498	      });
499	
500	      // Cache session ID from response
501	      const newSessionId = response.headers.get('Mcp-Session-Id');
502	      if (newSessionId) {
503	        this.sessions.set(server.name, newSessionId);
504	      }
505	
506	      const contentType = response.headers.get('content-type') ?? '';
507	
508	      if (!response.ok) {
509	        const text = await response.text().catch(() => '');
510	        throw new Error(`Upstream ${server.name} returned HTTP ${response.status}: ${text.slice(0, 200)}`);
511	      }
512	
513	      // Handle non-JSON responses gracefully
514	      if (!contentType.includes('application/json') && !contentType.includes('text/plain')) {
515	        const text = await response.text();
516	        log.warn('Non-JSON upstream response', { server: server.name, method, contentType });
517	        // Try to parse as JSON anyway
518	        try {
519	          const data = JSON.parse(text);
520	          if (data.error) {
521	            throw new Error(`MCP error from ${server.name}: ${data.error.message ?? JSON.stringify(data.error)}`);
522	          }
523	          return data.result as T;
524	        } catch {
525	          // If it's not JSON at all, return as text content
526	          return { content: [{ type: 'text', text }] } as unknown as T;
527	        }
528	      }
529	
530	      const data = (await response.json()) as { error?: { message?: string }; result?: T };
531	
532	      if (data.error) {
533	        throw new Error(`MCP error from ${server.name}: ${data.error.message ?? JSON.stringify(data.error)}`);
534	      }
535	
536	      return data.result as T;
537	    } catch (err) {
538	      if (err instanceof DOMException && err.name === 'AbortError') {
539	        throw new Error(`Upstream ${server.name} timed out after ${MCP_CALL_TIMEOUT_MS}ms`);
540	      }
541	      throw err;
542	    } finally {
543	      clearTimeout(timeout);
544	      // Release concurrency slot
545	      const cur = this.activeConnections.get(server.name) ?? 1;
546	      if (cur <= 1) {
547	        this.activeConnections.delete(server.name);
548	      } else {
549	        this.activeConnections.set(server.name, cur - 1);
550	      }
551	    }
552	  }
553	}
