1	/**
2	 * LayerInfinite MCP Server — config.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * V2 Gateway Configuration. Supports upstream MCP servers,
5	 * per-task-type mode overrides, shadow mode, and environment isolation.
6	 *
7	 * Backwards-compatible: all V1 env vars (LAYERINFINITE_API_KEY,
8	 * LAYERINFINITE_BASE_URL, LAYERINFINITE_MODE, LAYERINFINITE_ADMIN_KEY)
9	 * continue to work.
10	 * ══════════════════════════════════════════════════════════════
11	 */
12	
13	export type LIMode = 'recommend' | 'assist' | 'auto';
14	
15	export interface ClassifierConfig {
16	  enabled: boolean;
17	  apiKey: string | null;
18	  model: string;
19	  baseUrl: string;
20	  timeoutMs: number;
21	  cacheTtlMs: number;
22	}
23	
24	export interface UpstreamServer {
25	  /** Human-readable name. Used as tool prefix (e.g. "github" → "github_push_fix"). */
26	  readonly name: string;
27	  /** MCP server URL (e.g., "https://github-mcp.example.com"). */
28	  readonly url: string;
29	  /** Optional per-upstream API key. Falls back to LAYERINFINITE_API_KEY if unset. */
30	  readonly apiKey?: string;
31	  /** Health check interval in ms. Default 30_000. */
32	  readonly healthCheckIntervalMs?: number;
33	}
34	
35	export interface GatewayConfig {
36	  /** API key for authenticating with the LayerInfinite REST API. */
37	  readonly apiKey: string;
38	  /** Optional secondary API key for zero-downtime rotation. */
39	  readonly apiKeySecondary?: string;
40	  /** Base URL of the LayerInfinite API (no trailing slash). */
41	  readonly baseUrl: string;
42	  /** Global operating mode. null = bootstrap (observe only). */
43	  readonly mode: LIMode | null;
44	  /** Upstream MCP servers to proxy. */
45	  readonly upstreamServers: readonly UpstreamServer[];
46	  /** Per-task-type mode overrides. Key = task_type, value = mode. */
47	  readonly modeOverrides: ReadonlyMap<string, LIMode>;
48	  /** If true, LI observes and logs but does NOT inject enrichment. */
49	  readonly shadowMode: boolean;
50	  /** Deployment environment. Staging outcomes are isolated from production. */
51	  readonly environment: 'staging' | 'production';
52	  /** Admin key for gated operations. null = admin disabled. */
53	  readonly adminKey: string | null;
54	  /** Log level. Default derived from NODE_ENV. */
55	  readonly logLevel: 'debug' | 'info' | 'warn' | 'error';
56	  /** LLM outcome classifier config. null = classifier disabled. */
57	  readonly classifier: ClassifierConfig | null;
58	}
59	
60	const VALID_MODES: ReadonlySet<string> = new Set(['recommend', 'assist', 'auto']);
61	const VALID_ENVIRONMENTS: ReadonlySet<string> = new Set(['staging', 'production']);
62	
63	function parseUpstreamServers(raw: string): UpstreamServer[] {
64	  try {
65	    const parsed = JSON.parse(raw);
66	    if (!Array.isArray(parsed)) {
67	      throw new Error('LAYERINFINITE_UPSTREAM_TOOLS must be a JSON array');
68	    }
69	    return parsed.map((item: Record<string, unknown>, i: number) => {
70	      if (typeof item.name !== 'string' || item.name.trim() === '') {
71	        throw new Error(`Upstream server at index ${i}: "name" is required and must be a non-empty string`);
72	      }
73	      if (typeof item.url !== 'string' || item.url.trim() === '') {
74	        throw new Error(`Upstream server "${item.name}": "url" is required and must be a non-empty string`);
75	      }
76	      return {
77	        name: item.name.trim(),
78	        url: item.url.trim(),
79	        apiKey: typeof item.apiKey === 'string' ? item.apiKey : undefined,
80	        healthCheckIntervalMs: typeof item.healthCheckIntervalMs === 'number' ? item.healthCheckIntervalMs : undefined,
81	      };
82	    });
83	  } catch (err) {
84	    if (err instanceof SyntaxError) {
85	      throw new Error(`LAYERINFINITE_UPSTREAM_TOOLS is not valid JSON: ${err.message}`);
86	    }
87	    throw err;
88	  }
89	}
90	
91	function parseModeOverrides(raw: string): Map<string, LIMode> {
92	  if (!raw || raw.trim() === '' || raw.trim() === '{}') {
93	    return new Map();
94	  }
95	  try {
96	    const parsed = JSON.parse(raw);
97	    if (typeof parsed !== 'object' || parsed === null || Array.isArray(parsed)) {
98	      throw new Error('LAYERINFINITE_MODE_OVERRIDES must be a JSON object (e.g., {"build_failed":"auto"})');
99	    }
100	    const map = new Map<string, LIMode>();
101	    for (const [taskType, mode] of Object.entries(parsed)) {
102	      if (typeof mode !== 'string' || !VALID_MODES.has(mode)) {
103	        throw new Error(
104	          `LAYERINFINITE_MODE_OVERRIDES: invalid mode "${String(mode)}" for task "${taskType}". ` +
105	          `Valid values: recommend, assist, auto.`,
106	        );
107	      }
108	      map.set(taskType, mode as LIMode);
109	    }
110	    return map;
111	  } catch (err) {
112	    if (err instanceof SyntaxError) {
113	      throw new Error(`LAYERINFINITE_MODE_OVERRIDES is not valid JSON: ${err.message}`);
114	    }
115	    throw err;
116	  }
117	}
118	
119	/**
120	 * Reads and validates environment variables.
121	 * Throws immediately if required vars are missing — fail fast at startup.
122	 */
123	export function loadConfig(): GatewayConfig {
124	  // ── V1 backwards-compatible vars ──────────────────────────
125	  const apiKey = process.env.LAYERINFINITE_API_KEY;
126	  if (!apiKey || apiKey.trim() === '') {
127	    throw new Error(
128	      '[layerinfinite-mcp] LAYERINFINITE_API_KEY is required. ' +
129	      'Get your key from the LayerInfinite dashboard.',
130	    );
131	  }
132	
133	  const apiKeySecondary = process.env.LAYERINFINITE_API_KEY_2?.trim() || undefined;
134	
135	  const baseUrl = (process.env.LAYERINFINITE_BASE_URL ?? 'https://layerinfinite.me').replace(/\/+$/, '');
136	
137	  const rawMode = (process.env.LAYERINFINITE_MODE ?? '').trim().toLowerCase();
138	  let mode: LIMode | null = null;
139	  if (rawMode !== '') {
140	    if (!VALID_MODES.has(rawMode)) {
141	      throw new Error(
142	        `[layerinfinite-mcp] Invalid LAYERINFINITE_MODE="${rawMode}". ` +
143	        `Valid values: recommend, assist, auto. Omit for bootstrap mode.`,
144	      );
145	    }
146	    mode = rawMode as LIMode;
147	  }
148	
149	  const adminKey = process.env.LAYERINFINITE_ADMIN_KEY?.trim() || null;
150	
151	  // ── V2 new vars ──────────────────────────────────────────
152	  const rawUpstream = (process.env.LAYERINFINITE_UPSTREAM_TOOLS ?? '[]').trim();
153	  const upstreamServers = parseUpstreamServers(rawUpstream);
154	
155	  const rawOverrides = (process.env.LAYERINFINITE_MODE_OVERRIDES ?? '{}').trim();
156	  const modeOverrides = parseModeOverrides(rawOverrides);
157	
158	  const shadowMode = (process.env.LAYERINFINITE_SHADOW_MODE ?? 'false').trim().toLowerCase() === 'true';
159	
160	  const rawEnv = (process.env.LAYERINFINITE_ENVIRONMENT ?? 'production').trim().toLowerCase();
161	  if (!VALID_ENVIRONMENTS.has(rawEnv)) {
162	    throw new Error(
163	      `[layerinfinite-mcp] Invalid LAYERINFINITE_ENVIRONMENT="${rawEnv}". ` +
164	      `Valid values: staging, production.`,
165	    );
166	  }
167	  const environment = rawEnv as 'staging' | 'production';
168	
169	  const logLevel = resolveLogLevel();
170	
171	  // ── Classifier config ─────────────────────────────────────
172	  let classifier: ClassifierConfig | null = null;
173	  if ((process.env.LI_CLASSIFIER_ENABLED ?? '').toLowerCase() === 'true') {
174	    classifier = {
175	      enabled: true,
176	      apiKey: process.env.LI_CLASSIFIER_API_KEY ?? process.env.OPENAI_API_KEY ?? null,
177	      model: process.env.LI_CLASSIFIER_MODEL ?? 'gpt-4o-mini',
178	      baseUrl: (process.env.LI_CLASSIFIER_BASE_URL ?? 'https://api.openai.com/v1').replace(/\/+$/, ''),
179	      timeoutMs: Number.parseInt(process.env.LI_CLASSIFIER_TIMEOUT_MS ?? '3000', 10) || 3000,
180	      cacheTtlMs: Number.parseInt(process.env.LI_CLASSIFIER_CACHE_TTL_MS ?? '300000', 10) || 300000,
181	    };
182	  }
183	
184	  const config: GatewayConfig = Object.freeze({
185	    apiKey,
186	    apiKeySecondary,
187	    baseUrl,
188	    mode,
189	    upstreamServers,
190	    modeOverrides,
191	    shadowMode,
192	    environment,
193	    adminKey,
194	    logLevel,
195	    classifier,
196	  });
197	
198	  return config;
199	}
200	
201	function resolveLogLevel(): GatewayConfig['logLevel'] {
202	  const raw = (process.env.LAYERINFINITE_LOG_LEVEL ?? '').trim().toLowerCase();
203	  if (['debug', 'info', 'warn', 'error'].includes(raw)) {
204	    return raw as GatewayConfig['logLevel'];
205	  }
206	  // Derive from NODE_ENV
207	  if (process.env.NODE_ENV === 'production') return 'info';
208	  if (process.env.NODE_ENV === 'test') return 'error';
209	  return 'debug';
210	}
