1	/**
2	 * LayerInfinite MCP Server — decision-tracker.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * Decision ID generation + episode tracking + buffer flush.
5	 * Replaces episode-tracker.ts (V1 redirect-loop prevention).
6	 *
7	 * Decision ID format: dec_{ts12}_{agent4}_{rand4}
8	 *   ts12    — base62-encoded timestamp (lexicographically sortable)
9	 *   agent4  — base62-encoded djb2 hash of agentId
10	 *   rand4   — 4 random base62 chars (collision prob < 10^-9 per ms)
11	 *
12	 * Buffer flushes every 5s to LI API. Disk queue fallback at
13	 * .li-queue/decisions.jsonl when API is unreachable.
14	 * ══════════════════════════════════════════════════════════════
15	 */
16	
17	import { appendFileSync, mkdirSync, existsSync } from 'node:fs';
18	import { join } from 'node:path';
19	import { randomBytes } from 'node:crypto';
20	import type { DecisionRecord, Episode } from './types.js';
21	import type { LiApiClient } from './rest-client.js';
22	import { logger } from './logger.js';
23	
24	const log = logger.forTool('decision-tracker');
25	
26	// ── Decision ID generation ──────────────────────────────────
27	
28	const BASE62 = '0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz';
29	const FLUSH_INTERVAL_MS = 5_000;
30	const EPISODE_TTL_MS = 30 * 60 * 1000;
31	const MAX_COACHING_PER_EPISODE = 3;
32	const DISK_QUEUE_DIR = '.li-queue';
33	const DISK_QUEUE_FILE = 'decisions.jsonl';
34	const MAX_BUFFER_SIZE = 10_000;
35	
36	function base62Encode(n: number, minLen: number): string {
37	  let s = '';
38	  let v = n;
39	  while (v > 0) {
40	    s = BASE62[v % 62] + s;
41	    v = Math.floor(v / 62);
42	  }
43	  return s.padStart(minLen, '0');
44	}
45	
46	function djb2(s: string): number {
47	  let hash = 5381;
48	  for (let i = 0; i < s.length; i++) {
49	    hash = ((hash << 5) + hash) + s.charCodeAt(i);
50	    hash = hash >>> 0;
51	  }
52	  return hash;
53	}
54	
55	function randomBase62(len: number): string {
56	  let s = '';
57	  const bytes = randomBytes(len);
58	  for (let i = 0; i < len; i++) {
59	    s += BASE62[bytes[i] % 62];
60	  }
61	  return s;
62	}
63	
64	export function generateDecisionId(agentId: string): string {
65	  const ts12 = base62Encode(Date.now(), 12);
66	  const agent4 = base62Encode(djb2(agentId), 4).slice(0, 4);
67	  const rand4 = randomBase62(4);
68	  return `dec_${ts12}_${agent4}_${rand4}`;
69	}
70	
71	function generateEpisodeId(): string {
72	  const ts10 = base62Encode(Date.now(), 10);
73	  const rand6 = randomBase62(6);
74	  return `ep_${ts10}_${rand6}`;
75	}
76	
77	// ══════════════════════════════════════════════════════════════
78	// DecisionTracker
79	// ══════════════════════════════════════════════════════════════
80	
81	export class DecisionTracker {
82	  private readonly episodes = new Map<string, Episode>();
83	  private readonly buffer: DecisionRecord[] = [];
84	  private flushTimer: ReturnType<typeof setInterval> | null = null;
85	  private flushing = false;
86	  private queueDirEnsured = false;
87	
88	  constructor(
89	    private readonly liApi: LiApiClient,
90	    private readonly environment: 'staging' | 'production',
91	  ) {}
92	
93	  // ── Episode management ───────────────────────────────────
94	
95	  startEpisode(agentId: string, customerId: string): Episode {
96	    this.cleanExpiredEpisodes();
97	
98	    const episode: Episode = {
99	      episodeId: generateEpisodeId(),
100	      agentId,
101	      sessionStart: new Date().toISOString(),
102	      decisions: [],
103	      coachingCount: 0,
104	    };
105	
106	    this.episodes.set(episode.episodeId, episode);
107	    log.debug('Episode started', { episodeId: episode.episodeId, agentId, customerId });
108	    return episode;
109	  }
110	
111	  getEpisode(episodeId: string): Episode | undefined {
112	    this.cleanExpiredEpisodes();
113	    return this.episodes.get(episodeId);
114	  }
115	
116	  /** Record a coaching injection. Returns false if cap (3) already reached. */
117	  recordCoaching(episodeId: string): boolean {
118	    const episode = this.episodes.get(episodeId);
119	    if (!episode) return false;
120	    if (episode.coachingCount >= MAX_COACHING_PER_EPISODE) return false;
121	    episode.coachingCount++;
122	    return true;
123	  }
124	
125	  canCoach(episodeId: string): boolean {
126	    const episode = this.episodes.get(episodeId);
127	    if (!episode) return true; // No episode yet — coaching is allowed
128	    return episode.coachingCount < MAX_COACHING_PER_EPISODE;
129	  }
130	
131	  // ── Decision recording ───────────────────────────────────
132	
133	  recordDecision(record: DecisionRecord): void {
134	    if (this.buffer.length >= MAX_BUFFER_SIZE) {
135	      this.buffer.shift();
136	      log.warn('Decision buffer full — dropping oldest entry');
137	    }
138	    this.buffer.push(record);
139	
140	    // Link to episode
141	    if (this.episodes.size > 0) {
142	      // Find the most recent episode for this agent
143	      let latest: Episode | undefined;
144	      for (const ep of this.episodes.values()) {
145	        if (ep.agentId === record.agentId) {
146	          if (!latest || ep.sessionStart > latest.sessionStart) {
147	            latest = ep;
148	          }
149	        }
150	      }
151	      if (latest) {
152	        latest.decisions.push(record.decisionId);
153	      }
154	    }
155	
156	    // Append to disk queue for durability
157	    this.appendToDiskQueue(record);
158	
159	    log.debug('Decision recorded', { decisionId: record.decisionId });
160	  }
161	
162	  // ── Flush ────────────────────────────────────────────────
163	
164	  async flushBuffer(): Promise<void> {
165	    if (this.buffer.length === 0 || this.flushing) return;
166	
167	    this.flushing = true;
168	    const batch = this.buffer.splice(0);
169	
170	    try {
171	      // Send each decision's outcome to LI API
172	      for (const record of batch) {
173	        const sent = await this.liApi.logOutcome({
174	          agent_id: record.agentId,
175	          customer_id: record.customerId,
176	          issue_type: record.taskType,
177	          action_name: record.actionName,
178	          upstream_name: record.upstreamName,
179	          original_action: record.originalAction,
180	          executed_action: record.executedAction,
181	          mode: record.mode,
182	          rerouted: record.rerouted,
183	          success: true,
184	          response_time_ms: 0,
185	          timestamp: record.timestamp,
186	          ingestion_source: 'mcp',
187	          environment: this.environment,
188	        });
189	
190	        if (!sent) {
191	          // Re-queue on failure
192	          this.buffer.push(record);
193	        }
194	      }
195	    } catch (err) {
196	      log.warn('Buffer flush failed — re-queuing', {
197	        count: batch.length,
198	        error: err instanceof Error ? err.message : String(err),
199	      });
200	      this.buffer.push(...batch);
201	    } finally {
202	      this.flushing = false;
203	    }
204	  }
205	
206	  startFlushTimer(): void {
207	    if (this.flushTimer) return;
208	    this.flushTimer = setInterval(() => {
209	      void this.flushBuffer();
210	    }, FLUSH_INTERVAL_MS);
211	  }
212	
213	  stopFlushTimer(): void {
214	    if (this.flushTimer) {
215	      clearInterval(this.flushTimer);
216	      this.flushTimer = null;
217	    }
218	  }
219	
220	  // ── Stats ────────────────────────────────────────────────
221	
222	  get bufferSize(): number {
223	    return this.buffer.length;
224	  }
225	
226	  get episodeCount(): number {
227	    this.cleanExpiredEpisodes();
228	    return this.episodes.size;
229	  }
230	
231	  // ── Private ──────────────────────────────────────────────
232	
233	  private appendToDiskQueue(record: DecisionRecord): void {
234	    try {
235	      if (!this.queueDirEnsured) {
236	        if (!existsSync(DISK_QUEUE_DIR)) {
237	          mkdirSync(DISK_QUEUE_DIR, { recursive: true });
238	        }
239	        this.queueDirEnsured = true;
240	      }
241	      appendFileSync(
242	        join(DISK_QUEUE_DIR, DISK_QUEUE_FILE),
243	        JSON.stringify(record) + '\n',
244	        'utf-8',
245	      );
246	    } catch {
247	      // Disk queue is best-effort — silent failure is acceptable
248	    }
249	  }
250	
251	  private cleanExpiredEpisodes(): void {
252	    const cutoff = Date.now() - EPISODE_TTL_MS;
253	    for (const [id, ep] of this.episodes) {
254	      if (new Date(ep.sessionStart).getTime() < cutoff) {
255	        this.episodes.delete(id);
256	      }
257	    }
258	  }
259	}
