270	const LogOutcomeBody = z.object({
271	    session_id: z.string().uuid().optional(),
272	    idempotency_key: z.string().max(255).optional(),
273	    action_name: z.string().min(1).max(255).optional(),
274	    // Legacy alias still used by older SDK/manual clients.
275	    action_id: z.string().optional(),
276	    action_id_input: z.string().optional(),
277	    action_params: z.record(z.string(), z.unknown()).optional(),
278	    issue_type: z
279	        .string()
280	        .min(1)
281	        .max(255)
282	        .transform(val => {
283	            // Canonicalize to match the import route's canonicalizeIssueType():
284	            // lowercase, spaces/hyphens → underscores, strip non-alphanumeric.
285	            // Ensures "Payment_Failed" from import and "payment_failed" from SDK
286	            // resolve to the same context_id and task_name bucket.
287	            const sanitized = sanitizeString(val, 255).trim();
288	            return sanitized
289	                .toLowerCase()
290	                .replace(/[\s\-]+/g, '_')
291	                .replace(/[^a-z0-9_]/g, '')
292	                .replace(/_+/g, '_')
293	                .replace(/^_+|_+$/g, '');
294	        })
295	        .refine(val => val.length > 0, { message: 'issue_type cannot be blank' }),
296	    success: z.preprocess(
297	        (val) => {
298	            if (typeof val === 'boolean') return val;
299	            if (typeof val === 'string') {
300	                const lower = val.trim().toLowerCase();
301	                if (['true', '1', 'yes', 'ok', 'pass', 'resolved'].includes(lower)) return true;
302	                if (['false', '0', 'no', 'fail', 'failed'].includes(lower)) return false;
303	            }
304	            if (typeof val === 'number') return val === 1;
305	            return val;
306	        },
307	        z.boolean(),
308	    ),
309	    response_time_ms: z.preprocess(
310	        (val) => {
311	            if (typeof val === 'number') {
312	                return Number.isFinite(val) && val > 0 ? Math.round(val) : undefined;
313	            }
314	            if (typeof val === 'string') {
315	                const parsed = Number(val);
316	                return Number.isFinite(parsed) && parsed > 0 ? Math.round(parsed) : undefined;
317	            }
318	            return val;
319	        },
320	        z.number().int().positive().optional(),
321	    ),
322	    response_ms: z.preprocess(
323	        (val) => {
324	            if (typeof val === 'number') {
325	                return Number.isFinite(val) && val > 0 ? Math.round(val) : undefined;
326	            }
327	            if (typeof val === 'string') {
328	                const parsed = Number(val);
329	                return Number.isFinite(parsed) && parsed > 0 ? Math.round(parsed) : undefined;
330	            }
331	            return val;
332	        },
333	        z.number().int().positive().optional(),
334	    ), // SDK alias — maps to response_time_ms
335	    error_code: z.string().max(100).optional(),
336	    error_message: z.string().max(1000).optional(),
337	    raw_context: z.record(z.string(), z.unknown()).optional(),
338	    // Any string is accepted. Common abbreviations are normalized.
339	    // Unknown values default to 'production'. Field is metadata-only —
340	    // not referenced by any conditional branch in scoring or policy.
341	    environment: z
342	        .string()
343	        .max(50)
344	        .optional()
345	        .default('production')
346	        .transform(val => {
347	            const normalized = val.trim().toLowerCase();
348	            const aliases: Record<string, string> = {
349	                'prod': 'production',
350	                'dev': 'development',
351	                'develop': 'development',
352	                'stage': 'staging',
353	                'stg': 'staging',
354	                'qa': 'staging',
355	                'test': 'staging',
356	                'uat': 'staging',
357	            };
358	            if (aliases[normalized]) return aliases[normalized] as 'production' | 'staging' | 'development';
359	            const known = ['production', 'staging', 'development'] as const;
360	            return (known as readonly string[]).includes(normalized)
361	                ? (normalized as typeof known[number])
362	                : 'production';
363	        }),
364	    customer_tier: z.enum(['free', 'pro', 'enterprise']).optional(),
365	
366	    outcome_score: z.preprocess(
367	        (val) => {
368	            if (val === undefined || val === null) return undefined;
369	            const num = Number(val);
370	            if (!Number.isFinite(num)) return val; // let Zod reject non-numeric
371	            // Percentage auto-detection: values >=2 and <=100 → divide by 100
372	            // Values between 1.0 and 2.0 are rejected as invalid (ambiguous range).
373	            if (num >= 2 && num <= 100) return num / 100;
374	            return num;
375	        },
376	        z.number().min(0.0).max(1.0, {
377	            message: 'outcome_score must be between 0.0 and 1.0 (or 2-100 for percentage)',
378	        }).optional(),
379	    ),
380	
381	    business_outcome: z
382	        .string()
383	        .max(100)
384	        .optional()
385	        .transform(val => {
386	            if (val === undefined || val === null) return undefined;
387	            const normalized = val.trim().toLowerCase();
388	            const known = ['resolved', 'partial', 'failed', 'unknown'] as const;
389	            return (known as readonly string[]).includes(normalized)
390	                ? (normalized as typeof known[number])
391	                : 'unknown';
392	        }),
393	    // Any string is accepted. Known values are normalized to lowercase.
394	    // Unknown values map to 'none' (neutral — no clear feedback signal).
395	    // Field is metadata-only — never read by scoring, trust, or policy.
396	    feedback_signal: z
397	        .string()
398	        .max(50)
399	        .optional()
400	        .transform(val => {
401	            if (val === undefined || val === null) return 'immediate';
402	            const normalized = val.trim().toLowerCase();
403	            const known = ['immediate', 'delayed', 'none'] as const;
404	            return (known as readonly string[]).includes(normalized)
405	                ? (normalized as typeof known[number])
406	                : 'none';
407	        }),
408	    decision_id: z.string().uuid().optional(),
409	    episode_id: z.string().uuid().optional(),
410	    episode_history: z.array(z.string()).optional(),
411	    verifier_signal: z.object({
412	        source: z.enum([
413	            'http_status_code',
414	            'database_row_count',
415	            'human_review',
416	            'downstream_webhook',
417	            'none',
418	        ]),
419	        value: z.union([
420	            z.number(),
421	            z.boolean(),
422	            z.string(),
423	        ]).optional(),
424	        verified_at: z.string().datetime().optional(),
425	    }).optional(),
426	
427	    // ── Phase 1: Real Outcome Signal Integration ──────────────
428	    // All four fields are optional. Callers that omit them get the
429	    // existing behaviour. real_agent.py sends none of them.
430	    signal_source: z.enum([
431	        'causal_graph',
432	        'signal_contract',
433	        'http_inference',
434	        'explicit',
435	    ]).optional().default('explicit'),
436	    // When signal_source is 'causal_graph', the Proxy interceptor
437	    // inferred which action this outcome belongs to.
438	    inferred_action_id: z.string().uuid().optional(),
439	    // Confidence of the signal: 0.90 at causal depth 0, decays by
440	    // 0.04 per depth level. NULL for explicit signals.
441	    causal_confidence: z.number().min(0).max(1).optional(),
442	    // How many transformation layers the traced value traversed.
443	    // NULL for explicit signals. 0–8 for causal graph signals.
444	    signal_depth: z.number().int().min(0).max(9).optional(),
445	
446	    // ── Decision Recommendation Engine ───────────────────────
447	    // Optional semantic label for what the agent was trying to do.
448	    // Examples: "payment_failed", "ticket_escalation", "refund_request"
449	    // If absent: auto-inferred from issue_type via inferTask().
450	    // TASK RESOLUTION RULE: provided value ALWAYS wins over inferred.
451	    task_name: z.string().min(1).max(255).optional(),
452	    retry_chain_id: z.string().uuid().optional(),
453	    retry_attempt: z.number().int().min(0).max(1000).optional(),
454	    execution_status: z
455	        .preprocess(
456	            (val) => typeof val === 'string' ? val.trim().toUpperCase() : val,
457	            z.enum(['COMPLETED', 'FAILED']).optional(),
458	        ),
459	    failure_reason_code: z.string().max(80).optional(),
460	    failure_stage: z.string().max(40).optional(),
461	
462	    // ── Resource cost tracking ────────────────────────────────
463	    // Tracks token usage, API call count, or compute cost per outcome.
464	    // Agent frameworks (LangChain, CrewAI) report token_usage.total_tokens;
465	    // this field captures that signal for cost-per-outcome analysis.
466	    resource_cost_units: z.preprocess(
