470	            return Number.isFinite(num) && num >= 0 ? num : undefined;
471	        },
472	        z.number().min(0).optional(),
473	    ),
474	    resource_cost_type: z.enum(['tokens', 'api_calls', 'compute_seconds']).optional(),
