1573	    return new Promise((resolve) => {
1574	        const timer = setTimeout(async () => {
1575	            _taskPerfRefreshTimers.delete(customerId);
1576	            try {
1577	                const { error } = await supabase.rpc('refresh_task_action_performance');
1578	                if (error) {
1579	                    // Log but never throw — refresh failure must not affect logging
1580	                    console.warn('[log-outcome] MV refresh RPC failed:', {
1581	                        customer_id: customerId,
1582	                        error: error.message,
1583	                        hint: 'Data is stale - check mv_tap_unique_idx exists in Supabase',
1584	                    });
1585	                } else {
