230	function deriveScoreConfidenceSource(params: {
231	    coldStart: boolean;
232	    shadowApplied: boolean;
233	    topConfidence: number | null;
234	}): { source: ConfidenceSource; reason: string } {
235	    if (params.coldStart) {
236	        return {
237	            source: 'bootstrap',
238	            reason: 'cold_start_or_unregistered_fallback',
239	        };
240	    }
241	    if (params.shadowApplied) {
242	        return {
243	            source: 'hybrid_shadow',
244	            reason: 'runtime_shadow_blend_applied',
245	        };
246	    }
247	    const topConfidence = params.topConfidence ?? 0;
248	    return topConfidence < 0.8
249	        ? {
250	            source: 'empirical_warmup',
251	            reason: 'top_confidence_below_stable_threshold',
252	        }
253	        : {
254	            source: 'empirical_stable',
255	            reason: 'top_confidence_stable',
256	        };
