260	    const normalized = String(reason ?? 'unknown_policy_reason').trim().toLowerCase();
261	    const mapped: Record<string, string> = {
262	        cold_start: 'cold_start_explore',
263	        agent_suspended: 'trust_gate_blocked',
264	        agent_new_no_history: 'new_agent_explore',
265	        conservative_high_score: 'policy_conservative_exploit',
266	        epsilon_greedy_exploit: 'policy_epsilon_greedy_exploit',
267	        epsilon_greedy_explore: 'policy_epsilon_greedy_explore',
268	        confidence_weighted_exploit: 'policy_confidence_weighted_exploit',
269	        confidence_weighted_explore: 'policy_confidence_weighted_explore',
270	        no_reliable_action: 'policy_escalate_no_reliable_action',
271	        default_exploration: 'policy_default_exploration',
272	        ambiguous_low_separation: 'policy_ambiguous_abstain',
273	        runtime_simulation_exploit_gate: 'simulation_exploit_gate',
274	        cold_start_unregistered_global_fallback: 'cold_start_unregistered_fallback',
275	    };
276	
277	    if (mapped[normalized]) {
278	        return mapped[normalized];
279	    }
280	
281	    return normalized.length > 0
282	        ? `policy_${normalized}`
283	        : 'unknown_policy_reason';
