286	function computeRuntimeShadowBlendWeight(
287	    sampleCount: number,
288	    rolloutConfig: ReturnType<typeof getRecommendationRolloutConfig>,
289	): number {
290	    if (sampleCount >= rolloutConfig.simulationShadowBlendUntilSamples) {
291	        return 0;
292	    }
293	
294	    const ratio =
295	        (rolloutConfig.simulationShadowBlendUntilSamples - sampleCount)
296	        / rolloutConfig.simulationShadowBlendUntilSamples;
297	    return Number(
298	        Math.min(rolloutConfig.simulationShadowBlendCap, ratio * rolloutConfig.simulationShadowBlendCap)
299	            .toFixed(4),
300	    );
301	}
