303	async function fetchRuntimeCounterfactualShadowSignals(
304	    actionIds: string[],
305	    customerId: string,
306	    agentId: string | undefined,
307	    rolloutConfig: ReturnType<typeof getRecommendationRolloutConfig>,
308	): Promise<Map<string, number>> {
309	    const uniqueActionIds = [...new Set(actionIds.filter(Boolean))];
310	    if (uniqueActionIds.length === 0) return new Map<string, number>();
311	
312	    let decisionsQuery = supabase
313	        .from('fact_decisions')
314	        .select('id, dim_agents!inner(customer_id, agent_id)')
315	        .eq('dim_agents.customer_id', customerId)
316	        .order('created_at', { ascending: false })
317	        .limit(rolloutConfig.simulationShadowDecisionLookback);
318	
319	    if (agentId) {
320	        decisionsQuery = decisionsQuery.eq('agent_id', agentId);
321	    }
322	
323	    const { data: decisions, error: decisionError } = await decisionsQuery;
324	    if (decisionError) {
325	        console.warn('[get-scores] runtime shadow decision lookup failed:', decisionError.message);
326	        return new Map<string, number>();
327	    }
328	
329	    const decisionIds = (decisions ?? [])
330	        .map((decision: any) => decision.id)
331	        .filter((value: unknown): value is string => typeof value === 'string' && value.length > 0);
332	
333	    if (decisionIds.length === 0) {
334	        return new Map<string, number>();
335	    }
336	
337	    const chunks: string[][] = [];
338	    for (let idx = 0; idx < decisionIds.length; idx += RUNTIME_SIMULATION_SHADOW_DECISION_CHUNK_SIZE) {
339	        chunks.push(decisionIds.slice(idx, idx + RUNTIME_SIMULATION_SHADOW_DECISION_CHUNK_SIZE));
340	    }
341	
342	    const chunkRows = await Promise.all(chunks.map(async (chunk, chunkIndex) => {
343	        const { data, error } = await supabase
344	            .from('fact_outcome_counterfactuals')
345	            .select('unchosen_action_id, counterfactual_est, ips_weight, created_at')
346	            .in('decision_id', chunk)
347	            .in('unchosen_action_id', uniqueActionIds)
348	            .order('created_at', { ascending: false })
349	            .limit(rolloutConfig.simulationShadowRecentPerAction * uniqueActionIds.length);
350	
351	        if (error) {
352	            console.warn(
353	                '[get-scores] runtime shadow counterfactual lookup failed:',
354	                error.message,
355	                '| chunk:',
356	                chunkIndex,
357	            );
358	            return [] as RuntimeCounterfactualSignalRow[];
359	        }
360	
361	        return (data ?? []) as RuntimeCounterfactualSignalRow[];
362	    }));
363	
364	    const dedupedRows = new Map<string, RuntimeCounterfactualSignalRow>();
365	    for (const row of chunkRows.flat()) {
366	        if (!row.unchosen_action_id || !row.created_at) continue;
367	        const key = `${row.unchosen_action_id}:${row.created_at}`;
368	        if (!dedupedRows.has(key)) dedupedRows.set(key, row);
369	    }
370	
371	    const grouped = new Map<string, RuntimeCounterfactualSignalRow[]>();
372	    for (const row of dedupedRows.values()) {
373	        if (!row.unchosen_action_id) continue;
374	        const existing = grouped.get(row.unchosen_action_id) ?? [];
375	        existing.push(row);
376	        grouped.set(row.unchosen_action_id, existing);
377	    }
378	
379	    const signals = new Map<string, number>();
380	    for (const actionId of uniqueActionIds) {
381	        const rows = (grouped.get(actionId) ?? [])
382	            .sort(
383	                (a, b) => new Date(b.created_at ?? 0).getTime() - new Date(a.created_at ?? 0).getTime(),
384	            )
385	            .slice(0, rolloutConfig.simulationShadowRecentPerAction);
386	
387	        if (rows.length === 0) continue;
388	
389	        let weightedTotal = 0;
390	        let weightTotal = 0;
391	        let simpleTotal = 0;
392	
393	        for (const row of rows) {
394	            const estimate = clamp01(Number(row.counterfactual_est ?? 0));
395	            const weight = clamp01(Number(row.ips_weight ?? 0));
396	            simpleTotal += estimate;
397	            if (weight > 0) {
398	                weightedTotal += estimate * weight;
399	                weightTotal += weight;
400	            }
401	        }
402	
403	        const signal = weightTotal > 0
404	            ? weightedTotal / weightTotal
405	            : simpleTotal / rows.length;
406	        signals.set(actionId, Number(clamp01(signal).toFixed(4)));
407	    }
408	
409	    return signals;
410	}
