832	            && rolloutConfig.simulationConfidenceCeilingEnabled
833	            && topForGuardrail
834	            && runtimeGuardrail.top_action_shadow_weight > 0
835	            && topForGuardrail.confidence > rolloutConfig.simulationConfidenceCeiling
836	        ) {
837	            const capped = Number(rolloutConfig.simulationConfidenceCeiling.toFixed(4));
838	            ranked = ranked.map((action) =>
