126	function medianOf(values: number[]): number | null {
127	    const finite = values.filter((v) => Number.isFinite(v)).sort((a, b) => a - b);
128	    if (finite.length === 0) return null;
129	
130	    const middle = Math.floor(finite.length / 2);
131	    if (finite.length % 2 === 1) {
132	        return Number(finite[middle].toFixed(4));
133	    }
134	
135	    return Number(((finite[middle - 1] + finite[middle]) / 2).toFixed(4));
136	}
