302	function addOutcomeCount(
303	    agentTaskTotals: Map<string, Map<string, number>>,
304	    agentGrandTotals: Map<string, number>,
305	    agentSuccessStats: Map<string, { wins: number; rated: number }>,
306	    agentId: string,
307	    taskName: string,
308	    increment: number,
309	    success: boolean | null,
310	    score: number | null,
311	    scoreRaw: number | null,
312	): void {
313	    if (!agentId || !taskName || !Number.isFinite(increment) || increment <= 0) {
314	        return;
315	    }
316	
317	    let taskMap = agentTaskTotals.get(agentId);
318	    if (!taskMap) {
319	        taskMap = new Map<string, number>();
320	        agentTaskTotals.set(agentId, taskMap);
321	    }
322	
323	    taskMap.set(taskName, (taskMap.get(taskName) ?? 0) + increment);
324	    agentGrandTotals.set(agentId, (agentGrandTotals.get(agentId) ?? 0) + increment);
325	
326	    // Track win rate across all tasks for this agent
327	    const stats = agentSuccessStats.get(agentId) ?? { wins: 0, rated: 0 };
328	    const finalScore = scoreRaw ?? score ?? (success === true ? 1 : success === false ? 0 : null);
329	    if (finalScore !== null) {
330	        stats.rated += increment;
331	        stats.wins += (finalScore * increment);
332	        agentSuccessStats.set(agentId, stats);
333	    }
334	}
