524	    if (!rawTask) {
525	        return c.json({ error: 'Missing required query parameter: task', code: 'MISSING_TASK' }, 400);
526	    }
527	    if (!rawAgentId) {
528	        return c.json({ error: 'Missing required query parameter: agent_id', code: 'MISSING_AGENT_ID' }, 400);
529	    }
