533	        // The drift query is limited to a recent window; action aggregates are all-time.
534	        // Action aggregates are needed when trust gate blocks the engine (all_actions=[]).
535	        const [driftResult, actionResult] = await Promise.all([
536	            supabase
537	                .from('fact_outcomes')
538	                .select('success, outcome_score, outcome_score_raw, execution_status, failure_reason_code, cross_event_status, is_synthetic, timestamp, data_quality')
539	                .eq('customer_id', customerId)
540	                .eq('agent_id', rawAgentId)
541	                .eq('task_name', rawTask)
542	                .eq('is_deleted', false)
543	                .eq('is_synthetic', false)
544	                .order('timestamp', { ascending: false })
545	                .limit(windowSize * 2),
546	            supabase
547	                .from('fact_outcomes')
548	                .select('action_id, outcome_score, outcome_score_raw, success, execution_status, timestamp, dim_actions(action_name)')
