562	        const rows = (driftResult.data ?? []) as Array<{
563	            success: boolean | null;
564	            outcome_score: number | null;
565	            outcome_score_raw: number | null;
566	            execution_status: string | null;
567	            failure_reason_code: string | null;
568	            cross_event_status: string | null;
569	            is_synthetic: boolean | null;
570	            timestamp: string | null;
571	            data_quality: number | null;
